syntax.postgresql:
-- Create a schema
CREATE SCHEMA billing;

-- Create objects in the schema
CREATE TABLE billing.invoices (
  id SERIAL PRIMARY KEY,
  user_id INT NOT NULL,
  amount NUMERIC(10, 2) NOT NULL,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

-- Set the search path to include the schema
SET search_path TO public, billing;

-- Grant usage on a schema
GRANT USAGE ON SCHEMA billing TO app_role;
GRANT SELECT ON ALL TABLES IN SCHEMA billing TO app_role;

syntax.mysql:
-- In MySQL, 'schema' and 'database' are synonymous
CREATE DATABASE billing;

-- Create objects in the database
CREATE TABLE billing.invoices (
  id INT AUTO_INCREMENT PRIMARY KEY,
  user_id INT NOT NULL,
  amount DECIMAL(10, 2) NOT NULL,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Access tables across databases
SELECT u.username, i.amount
FROM users u
JOIN billing.invoices i ON i.user_id = u.id;

syntax.mariadb:
-- In MariaDB, 'schema' and 'database' are synonymous
