-- Access tables across databases
SELECT u.username, i.amount
FROM users u
JOIN billing.invoices i ON i.user_id = u.id;

syntax.postgresql:
-- List available extensions
SELECT * FROM pg_available_extensions;

-- Install an extension
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE EXTENSION IF NOT EXISTS pg_trgm;
CREATE EXTENSION IF NOT EXISTS pgcrypto;

-- Use extension functions
SELECT uuid_generate_v4();  -- from uuid-ossp
SELECT gen_random_uuid();    -- built-in since PG 13

-- Fuzzy text search with pg_trgm
SELECT name, similarity(name, 'keybaord') AS sim
FROM products
WHERE name % 'keybaord'
ORDER BY sim DESC;

-- View installed extensions
SELECT * FROM pg_extension;

syntax.mysql:
-- MySQL uses plugins instead of extensions
-- List installed plugins
SHOW PLUGINS;

-- Install a plugin (example: clone plugin)
INSTALL PLUGIN clone SONAME 'mysql_clone.so';

-- Common built-in features that require no plugin:
-- UUID: SELECT UUID();
-- SHA2: SELECT SHA2('password', 256);

syntax.mariadb:
-- MariaDB uses plugins
-- List installed plugins
SHOW PLUGINS;

-- Install a plugin
INSTALL SONAME 'ha_connect';

-- Common built-in features:
-- UUID: SELECT UUID();
-- SHA2: SELECT SHA2('password', 256);

syntax.postgresql:
-- Install the postgres_fdw extension
CREATE EXTENSION postgres_fdw;

-- Create a foreign server
CREATE SERVER remote_db
  FOREIGN DATA WRAPPER postgres_fdw
  OPTIONS (host 'remote-server.example.com', port '5432', dbname 'production');

-- Create user mapping
CREATE USER MAPPING FOR current_user
  SERVER remote_db
  OPTIONS (user 'remote_user', password 'remote_pass');

-- Import tables from the remote schema
IMPORT FOREIGN SCHEMA public
  FROM SERVER remote_db
  INTO local_schema;

-- Or create individual foreign tables
CREATE FOREIGN TABLE remote_users (
  id INT,
  username VARCHAR(50),
  email VARCHAR(100)
) SERVER remote_db OPTIONS (table_name 'users');

-- Query as if it's a local table
SELECT * FROM remote_users WHERE username = 'admin';

-- Create a tablespace on a fast SSD
CREATE TABLESPACE fast_storage
  LOCATION '/mnt/ssd/pgdata';

-- Create a tablespace on slower, larger storage
CREATE TABLESPACE archive_storage
  LOCATION '/mnt/hdd/pgdata';

-- Create a table in a specific tablespace
CREATE TABLE orders (
  id SERIAL PRIMARY KEY,
  user_id INT NOT NULL,
  total NUMERIC(10, 2)
) TABLESPACE fast_storage;

-- Move an existing table to a different tablespace
ALTER TABLE orders SET TABLESPACE archive_storage;

-- Create an index in a specific tablespace
CREATE INDEX idx_orders_user ON orders(user_id) TABLESPACE fast_storage;

syntax.mysql:
-- Create a tablespace (InnoDB file-per-table)
CREATE TABLESPACE my_tablespace
  ADD DATAFILE 'my_tablespace.ibd'
  ENGINE = InnoDB;

-- Create a table in the tablespace
CREATE TABLE orders (
  id INT AUTO_INCREMENT PRIMARY KEY,
  user_id INT NOT NULL,
  total DECIMAL(10, 2)
) TABLESPACE my_tablespace;

syntax.mariadb:
-- MariaDB uses InnoDB tablespaces
CREATE TABLESPACE my_tablespace
  ADD DATAFILE 'my_tablespace.ibd'
  ENGINE = InnoDB;

-- Create a table in the tablespace
CREATE TABLE orders (
  id INT AUTO_INCREMENT PRIMARY KEY,
  user_id INT NOT NULL,
  total DECIMAL(10, 2)
) TABLESPACE my_tablespace;

syntax.postgresql:
-- Create a table with a specific collation
CREATE TABLE products (
  id SERIAL PRIMARY KEY,
  name VARCHAR(100) COLLATE "en_US.utf8" NOT NULL,
  name_ci VARCHAR(100) COLLATE "en-US-x-icu" NOT NULL  -- ICU collation
);

-- Case-insensitive collation per query
SELECT * FROM products
WHERE name COLLATE "en-x-icu" = 'keyboard';

-- Create a custom collation
CREATE COLLATION case_insensitive (
  PROVIDER = icu,
  LOCALE = 'und-u-ks-level2',
  DETERMINISTIC = FALSE
);

-- List available collations
SELECT collname, collprovider FROM pg_collation LIMIT 20;

syntax.mysql:
-- Create a table with a specific collation
CREATE TABLE products (
  id INT AUTO_INCREMENT PRIMARY KEY,
  name VARCHAR(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL
);

-- Case-insensitive comparison (default with _ci collation)
SELECT * FROM products WHERE name = 'Keyboard';  -- matches 'keyboard', 'KEYBOARD'

-- Case-sensitive comparison
SELECT * FROM products WHERE name COLLATE utf8mb4_bin = 'Keyboard';

-- Show available collations
SHOW COLLATION WHERE Charset = 'utf8mb4';

